const items = $input.all();

const STRAVA_TYPES = {
  'Ride':'Radtour','Run':'Lauf','Walk':'Spaziergang','Hike':'Wanderung',
  'Swim':'Schwimmen','WeightTraining':'Krafttraining','Workout':'Workout',
  'VirtualRide':'Virtual Ride','AlpineSki':'Skifahren','NordicSki':'Langlauf',
  'Snowboard':'Snowboard','RockClimbing':'Klettern','Kayaking':'Kajak'
};
const KOMOOT_TYPES = {
  'hike':'Wanderung','hiking':'Wanderung',
  'bike':'Radtour','cycling':'Radtour','road_cycling':'Radtour','citybike':'Radtour',
  'mtb':'MTB','mtb_easy':'MTB','mtb_advanced':'MTB','mtb_enduro':'MTB',
  'run':'Lauf','jogging':'Lauf','running':'Lauf',
  'nordic_walking':'Nordic Walking','walking':'Spaziergang',
  'climbing':'Klettern','ski_tour':'Skitouren','snowshoeing':'Schneeschuhwandern',
  'e_bike':'E-Bike','gravel_cycling':'Gravel'
};
const SPORT_EMOJI = {
  'Radtour':'🚴','MTB':'🚵','E-Bike':'🚴','Gravel':'🚴','Virtual Ride':'🖥',
  'Lauf':'🏃','Wanderung':'🥾','Spaziergang':'🚶','Nordic Walking':'🚶',
  'Schwimmen':'🏊','Krafttraining':'🏋','Workout':'💪',
  'Klettern':'🧗','Skifahren':'⛷️','Langlauf':'🏂','Skitouren':'⛷️',
  'Snowboard':'🏂','Schneeschuhwandern':'❄️','Kajak':'🚣'
};

function fmtDuration(secs) {
  const mins = Math.round(secs / 60);
  const h = Math.floor(mins / 60), m = mins % 60;
  return h > 0 ? h + 'h ' + m + 'min' : m + ' min';
}
function fmtLabel(type, fallback) {
  const t = type || '';
  return (SPORT_EMOJI[t] || '🏅') + ' ' + (t || fallback || 'Aktivitaet');
}

// --- Parse Strava (items[0]) ---
let stravaDate = null, stravaResult = null;
if (items.length > 0 && items[0].json && items[0].json.start_date) {
  const a = items[0].json;
  const sportRaw = a.sport_type || a.type || 'Aktivitaet';
  const sport = STRAVA_TYPES[sportRaw] || sportRaw;
  stravaDate = new Date(a.start_date);
  stravaResult = {
    name: a.name || 'Unbekannte Tour',
    sport: sportRaw, sportLabel: fmtLabel(sport, sportRaw),
    km: parseFloat(((a.distance || 0) / 1000).toFixed(1)),
    duration: fmtDuration(a.moving_time || 0),
    durationMins: Math.round((a.moving_time || 0) / 60),
    elevation: Math.round(a.total_elevation_gain || 0),
    avgSpeed: parseFloat(((a.average_speed || 0) * 3.6).toFixed(1)),
    heartrate: a.average_heartrate ? Math.round(a.average_heartrate) : null,
    date: new Date(a.start_date_local || a.start_date).toLocaleDateString('de-DE', {weekday:'short',day:'numeric',month:'long'}),
    startDate: a.start_date_local || a.start_date,
    kudos: a.kudos_count || 0,
    source: 'strava',
    stravaId: a.id, komootId: null, komootUrl: null
  };
}

// --- Parse Komoot (items[1]) ---
// n8n wraps HAL+JSON body as string in .data field
let komootDate = null, komootResult = null;
if (items.length > 1) {
  let raw = items[1].json;
  // Unwrap if n8n stored body as string
  if (raw && typeof raw.data === 'string') {
    try { raw = JSON.parse(raw.data); } catch(e) { raw = null; }
  }
  const tours = raw && raw._embedded && raw._embedded.tours;
  if (tours && tours.length > 0) {
    const t = tours[0];
    const sportRaw = t.sport || 'hike';
    const sport = KOMOOT_TYPES[sportRaw] || sportRaw;
    komootDate = new Date(t.date);
    komootResult = {
      name: t.name || 'Unbekannte Tour',
      sport: sportRaw, sportLabel: fmtLabel(sport, sportRaw),
      km: parseFloat(((t.distance || 0) / 1000).toFixed(1)),
      duration: fmtDuration(t.duration || 0),
      durationMins: Math.round((t.duration || 0) / 60),
      elevation: Math.round(t.elevation_up || 0),
      avgSpeed: t.duration > 0 ? parseFloat(((t.distance / t.duration) * 3.6).toFixed(1)) : 0,
      heartrate: null,
      date: new Date(t.date).toLocaleDateString('de-DE', {weekday:'short',day:'numeric',month:'long'}),
      startDate: t.date,
      kudos: 0,
      source: 'komoot',
      stravaId: null,
      komootId: t.id,
      komootUrl: 'https://www.komoot.com/tour/' + t.id
    };
  }
}

// --- Vergleich: neuere Tour gewinnt ---
let result;
if (stravaResult && komootResult) {
  result = (stravaDate >= komootDate) ? stravaResult : komootResult;
} else if (stravaResult) {
  result = stravaResult;
} else if (komootResult) {
  result = komootResult;
} else {
  return [{ json: { error: 'Keine Aktivitaet gefunden' } }];
}

return [{ json: result }];

